import java.io.*;import java.util.*;class Main{static class AllOne{HashMap<String,Integer>m=new HashMap<>();void inc(String k){m.put(k,m.getOrDefault(k,0)+1);}void dec(String k){int v=m.get(k)-1;if(v==0)m.remove(k);else m.put(k,v);}String max(){String best="";int val=-1;for(var e:m.entrySet()){String k=e.getKey();int v=e.getValue();if(v>val||(v==val&&(best.isEmpty()||k.compareTo(best)<0))){best=k;val=v;}}return best;}String min(){String best="";int val=1<<30;for(var e:m.entrySet()){String k=e.getKey();int v=e.getValue();if(v<val||(v==val&&(best.isEmpty()||k.compareTo(best)<0))){best=k;val=v;}}return best;}}static String q(String s,boolean nul){return nul?"null":"\""+s+"\"";}public static void main(String[]args)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[]d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int n=Integer.parseInt(d[idx++]);AllOne a=new AllOne();ArrayList<String>res=new ArrayList<>();for(int i=0;i<n;i++){String op=d[idx++];if(op.equals("C"))res.add(q("",true));else if(op.equals("I")){a.inc(d[idx++]);res.add(q("",true));}else if(op.equals("D")){a.dec(d[idx++]);res.add(q("",true));}else if(op.equals("X"))res.add(q(a.max(),false));else res.add(q(a.min(),false));}if(tc>0)out.append("\n\n");out.append("[").append(String.join(",",res)).append("]");}System.out.print(out);}}
